## 🔐 Code Review: PR #70 - SeededRandom Crypto Security Enhancement

I've completed a comprehensive review of this security enhancement. Overall, this is **excellent work** with a well-designed implementation. Here are my findings:

---

## ✅ Implementation Quality

### Core SeededRandom Changes (src/types/index.ts:342-380)

**Strengths:**
- ✅ **Proper Crypto API Usage**: `crypto.getRandomValues()` provides cryptographically secure entropy
- ✅ **Backward Compatibility**: Explicit seeds still work deterministically for gameplay mechanics
- ✅ **Environment Detection**: Smart fallback chain (crypto → Date.now())
- ✅ **Deterministic E2E Tests**: `__E2E_TEST__` flag enables fixed seed (577482274) for visual regression
- ✅ **Well-Tested**: 100% unit test coverage with proper mocking

**Security Assessment:**
- The fallback to `Date.now()` is **acceptable** for this game context (not cryptographic keys)
- The LCG algorithm `(state * 9301 + 49297) % 233280` is fine for game randomness
- No security vulnerabilities introduced

---

## ⚠️ SonarQube Quality Gate Blockers

### 1. Code Duplication: 28.7% (Critical - Blocking Merge)

**Root Cause:** Test helper functions are duplicated across 5 E2E test files.

**Specific Duplication Patterns:**

**Pattern A: Character Selection Flow** (16 occurrences)
```typescript
// Repeated in visual-regression.spec.ts, component-snapshots.spec.ts, 
// full-gameplay.spec.ts, game.spec.ts, character-classes.spec.ts
const charButton = page.getByRole('button', { name: /CHARACTER/ });
await charButton.click();
const commenceButton = page.getByRole('button', { name: /COMMENCE OPERATION/i });
await commenceButton.click();
```

**Pattern B: Animation Disabling** (8 occurrences in visual-regression.spec.ts)
```typescript
// Lines 21-46, 52-62 - duplicated helper functions
async function disableAnimations(page: Page) { /* 25 lines */ }
async function pauseThreeJsRendering(page: Page) { /* 11 lines */ }
```

**Pattern C: Game State Helpers** (duplicated in full-gameplay.spec.ts)
```typescript
// Lines 25-44, 46-58, 60-69, 71-108 - 4 helper functions totaling ~80 lines
async function getGameState(page: Page) { /* ... */ }
async function triggerStoreAction(page: Page, action: string, ...args: any[]) { /* ... */ }
async function waitForGameState(page: Page, expectedState: string) { /* ... */ }
async function simulateCombatUntilKills(page: Page, targetKills: number) { /* ... */ }
```

**Recommendation - Create Shared Test Helpers:**

Create `e2e/helpers/game-helpers.ts`:
```typescript
import { test, expect, type Page } from '@playwright/test';

/**
 * Helper to start the game with a specific character
 */
export async function startGame(page: Page, characterName: RegExp | string) {
  await page.waitForTimeout(2000);

  // Select Character
  const charButton = page.getByRole('button', { name: characterName });
  await charButton.waitFor({ state: 'visible', timeout: 30000 });
  await charButton.click({ force: true, timeout: 15000 });

  // Click COMMENCE OPERATION
  const commenceButton = page.getByRole('button', { name: /COMMENCE OPERATION/i });
  await commenceButton.waitFor({ state: 'visible', timeout: 30000 });
  await commenceButton.click({ force: true, timeout: 30000 });

  // Wait for game to load
  await expect(page.getByText('SCORE')).toBeVisible({ timeout: 30000 });
}

/**
 * Helper to disable animations for stable screenshots
 */
export async function disableAnimations(page: Page) {
  await page.addStyleTag({
    content: `
      *, *::before, *::after {
        animation-duration: 0s !important;
        transition-duration: 0s !important;
        animation-play-state: paused !important;
      }
    `
  });
  await page.evaluate(() => {
    return new Promise(resolve => requestAnimationFrame(() => requestAnimationFrame(resolve)));
  });
  await page.waitForTimeout(1000);
}

/**
 * Helper to pause Three.js rendering for stable snapshots
 */
export async function pauseThreeJsRendering(page: Page) {
  await page.evaluate(() => {
    window.__pauseGameForScreenshot = true;
  });
  await page.waitForTimeout(500);
}

/**
 * Get current game state from store
 */
export async function getGameState(page: Page) {
  return page.evaluate(() => {
    const store = (window as any).useGameStore;
    if (!store) return null;
    const state = store.getState();
    return {
      gameState: state.state,
      playerHp: state.playerHp,
      playerMaxHp: state.playerMaxHp,
      score: state.stats.score,
      kills: state.stats.kills,
      bossDefeated: state.stats.bossDefeated,
      bossActive: state.bossActive,
      bossHp: state.bossHp,
      killStreak: state.killStreak,
      enemyCount: state.enemies.length,
      bulletCount: state.bullets.length,
    };
  });
}

/**
 * Trigger game actions via store
 */
export async function triggerStoreAction(page: Page, action: string, ...args: any[]) {
  return page.evaluate(({ action, args }) => {
    const store = (window as any).useGameStore;
    if (!store) return false;
    const state = store.getState();
    if (typeof state[action] === 'function') {
      state[action](...args);
      return true;
    }
    return false;
  }, { action, args });
}

/**
 * Wait for specific game state
 */
export async function waitForGameState(page: Page, expectedState: string, timeout = 10000) {
  const startTime = Date.now();
  while (Date.now() - startTime < timeout) {
    const state = await getGameState(page);
    if (state?.gameState === expectedState) return true;
    await page.waitForTimeout(100);
  }
  return false;
}

/**
 * Simulate combat until target kills reached
 */
export async function simulateCombatUntilKills(page: Page, targetKills: number, maxTime = 30000) {
  const startTime = Date.now();
  await page.keyboard.down('Space');

  while (Date.now() - startTime < maxTime) {
    const state = await getGameState(page);
    if (!state || state.kills >= targetKills || state.gameState === 'GAME_OVER') break;

    const direction = Math.floor((Date.now() / 1000) % 4);
    await page.keyboard.up('w');
    await page.keyboard.up('a');
    await page.keyboard.up('s');
    await page.keyboard.up('d');

    switch (direction) {
      case 0: await page.keyboard.down('w'); break;
      case 1: await page.keyboard.down('d'); break;
      case 2: await page.keyboard.down('s'); break;
      case 3: await page.keyboard.down('a'); break;
    }

    await page.waitForTimeout(200);
  }

  await page.keyboard.up('Space');
  await page.keyboard.up('w');
  await page.keyboard.up('a');
  await page.keyboard.up('s');
  await page.keyboard.up('d');

  return getGameState(page);
}
```

**Then update all test files:**
```typescript
// visual-regression.spec.ts
import { startGame, disableAnimations, pauseThreeJsRendering } from './helpers/game-helpers';

// Remove duplicate helper functions (lines 21-110)
// Use imported helpers instead

// full-gameplay.spec.ts
